@Composable
fun rememberBubbleSelectionColors(
    bubbleBackground: Color,
    contentColor: Color,
    accentColor: Color = MaterialTheme.colorScheme.primary,
): TextSelectionColors {
    val bubbleLuminance = bubbleBackground.luminance()
    val contentLuminance = contentColor.luminance()
    return remember(bubbleBackground, contentColor, accentColor, bubbleLuminance, contentLuminance) {
        val useLightOverlay = bubbleLuminance < 0.32f && contentLuminance > 0.65f
        val overlayBase = if (useLightOverlay) Color.White else accentColor
        val overlayAlpha = when {
            useLightOverlay -> 0.28f
            bubbleLuminance > 0.88f -> 0.20f
            else -> 0.16f
        }
        TextSelectionColors(
            handleColor = if (useLightOverlay) Color.White else accentColor,
            backgroundColor = overlayBase.copy(alpha = overlayAlpha).compositeOver(bubbleBackground),
        )
    }
}

