/**
 * Computes selection colors guaranteed to contrast with [bubbleBackground].
 *
 * The previous implementation used [accentColor] (= primary) as the overlay base,
 * which made the selection highlight nearly invisible inside the user bubble
 * (whose background is also primary) and on dark-theme tonal surfaces. We now
 * always derive the overlay from [contentColor] - which Material 3 guarantees
 * to contrast with the bubble - and only use [accentColor] for the drag handles.
 */
@Composable
fun rememberBubbleSelectionColors(
    bubbleBackground: Color,
    contentColor: Color,
    accentColor: Color = MaterialTheme.colorScheme.primary,
): TextSelectionColors {
    val contentLuminance = contentColor.luminance()
    val accentContrast = kotlin.math.abs(accentColor.luminance() - bubbleBackground.luminance())
    return remember(bubbleBackground, contentColor, accentColor, contentLuminance, accentContrast) {
        // Light text on a dark bubble needs a stronger overlay to read; dark text
        // on a light bubble needs less to avoid muddying glyphs.
        val overlayAlpha = when {
            contentLuminance > 0.7f -> 0.34f
            contentLuminance > 0.4f -> 0.28f
            else -> 0.22f
        }
        // Handle uses accent only when accent itself contrasts with the bubble;
        // otherwise (e.g. user bubble where bubble == accent) fall back to content.
        val handle = if (accentContrast > 0.18f) accentColor else contentColor
        TextSelectionColors(
            handleColor = handle,
            backgroundColor = contentColor.copy(alpha = overlayAlpha).compositeOver(bubbleBackground),
        )
    }
}

