package com.piremote.ui.chat

import androidx.compose.foundation.text.selection.LocalTextSelectionColors
import androidx.compose.material3.LocalTextStyle
import androidx.compose.material3.MaterialTheme
import androidx.compose.runtime.Composable
import androidx.compose.runtime.CompositionLocalProvider
import androidx.compose.runtime.remember
import androidx.compose.ui.Modifier
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.graphics.toArgb
import androidx.compose.ui.platform.LocalUriHandler
import androidx.compose.ui.text.TextStyle
import dev.jeziellago.compose.markdowntext.MarkdownText

/**
 * Renders [text] as GitHub-flavored Markdown using the Markwon-backed
 * compose-markdown library. Falls back gracefully on plain strings.
 *
 * Supports: headings, bold/italic/strikethrough, ordered/unordered/task lists,
 * inline & fenced code, block quotes, tables, links (auto-linkified), and
 * inline images.
 */
@Composable
fun ChatMarkdown(
    text: String,
    color: Color,
    modifier: Modifier = Modifier,
    style: TextStyle = LocalTextStyle.current.merge(MaterialTheme.typography.bodyMedium),
    selectionColors: BubbleSelectionPalette = BubbleSelectionPalette(
        composeColors = androidx.compose.foundation.text.selection.TextSelectionColors(
            handleColor = color,
            backgroundColor = color.copy(alpha = 0.16f),
        ),
        textViewHighlight = color.copy(alpha = 0.24f),
    ),
    contextPath: String? = null,
    onDocumentLinkTap: (DocumentLinkTap) -> Unit = {},
) {
    val uriHandler = LocalUriHandler.current
    val renderedMarkdown = remember(text) { rewriteBareMarkdownPaths(text) }
    CompositionLocalProvider(LocalTextSelectionColors provides selectionColors.composeColors) {
        MarkdownText(
            markdown = renderedMarkdown,
            modifier = modifier,
            style = style.copy(color = color),
            linkColor = MaterialTheme.colorScheme.primary,
            isTextSelectable = true,
            autoSizeConfig = null,
            // Keep the library's default LinkMovementMethod: it supports long-press
            // text selection. Our OnTouchListener (installed below) runs before the
            // movement method and intercepts link taps, so the default is harmless.
            disableLinkMovementMethod = false,
            afterSetMarkdown = { textView ->
                // Markwon adds BackgroundColorSpan for inline code / fenced code blocks.
                // TextView draws those span backgrounds *after* the selection highlight,
                // which means selecting code text shows no highlight at all. We strip
                // the background spans here; code remains visually distinct via the
                // monospace TypefaceSpan that Markwon also applies.
                // Markwon uses its own *Code spans (InlineCodeSpan, CodeBlockSpan, etc.)
                // that draw their own backgrounds inside the span's draw() override.
                // TextView paints those backgrounds AFTER the selection highlight,
                // hiding it. Strip every Markwon span whose simple class name contains
                // "Code" so highlights remain visible. The TypefaceSpan that Markwon
                // also applies is a separate span and is preserved, so code keeps its
                // monospace font.
                (textView.text as? android.text.Spannable)?.let { spannable ->
                    val all = spannable.getSpans(0, spannable.length, Any::class.java)
                    for (span in all) {
                        val name = span.javaClass.simpleName
                        if (span is android.text.style.BackgroundColorSpan ||
                            name.contains("Code", ignoreCase = true) ||
                            name.contains("BlockQuote", ignoreCase = true)
                        ) {
                            spannable.removeSpan(span)
                        }
                    }
                }
                // Translucent highlight: blended on top of whatever is actually below
                // the glyphs at draw time. Safe now that span backgrounds are gone.
                textView.highlightColor = selectionColors.textViewHighlight.toArgb()
                textView.installMarkdownLinkTouchInterceptor(
                    contextPath = contextPath,
                    onDocumentLinkTap = onDocumentLinkTap,
                    onExternalLinkTap = { url -> uriHandler.openUri(url) },
                )
            },
        )
    }
}

