private data class UrlSpanHit(
    val url: String,
    val boundsInWindow: IntRect,
)

private fun TextView.findUrlSpanAt(event: MotionEvent): UrlSpanHit? {
    val spanned = text as? Spanned ?: return null
    val layout = layout ?: return null
    val x = (event.x - totalPaddingLeft + scrollX).toInt()
    val y = (event.y - totalPaddingTop + scrollY).toInt()
    if (x < 0 || y < 0 || x > layout.width || y > layout.height) return null
    val line = layout.getLineForVertical(y)
    val offset = layout.getOffsetForHorizontal(line, x.toFloat())
    val span = spanned.getSpans(offset, offset, URLSpan::class.java).firstOrNull()
        ?: if (offset > 0) spanned.getSpans(offset - 1, offset - 1, URLSpan::class.java).firstOrNull() else null
        ?: return null
    val start = spanned.getSpanStart(span)
    val end = spanned.getSpanEnd(span)
    return UrlSpanHit(
        url = span.url,
        boundsInWindow = computeSpanBoundsInWindow(spanned, layout, start, end),
    )
}

